pub fn l2_distance(a: &[f32], b: &[f32]) -> f64 {
    let mut sum_sq = 0.0f32;
    let n = a.len();
    for i in 0..n {
        let diff = a[i] - b[i];
        sum_sq += diff * diff;
    }
    (sum_sq as f64).sqrt()
}

use std::collections::BinaryHeap;
use std::sync::RwLock;
use crate::api::SearchResult;
use crate::distance::l2_distance;

pub struct VectorDB {
    vectors: RwLock<Vec<(u64, [f32; 128])>>,
}

impl VectorDB {
    pub fn new() -> Self {
        Self {
            vectors: RwLock::new(Vec::new()),
        }
    }

    pub fn insert(&self, id: u64, vector: Vec<f32>) {
        let v: [f32; 128] = vector.try_into().expect("Vector must be 128-dimensional");
        let mut vecs = self.vectors.write().expect("Lock poisoned");
        vecs.push((id, v));
    }

    pub fn bulk_insert(&self, vectors: Vec<(u64, Vec<f32>)>) -> usize {
        let mut vecs = self.vectors.write().expect("Lock poisoned");
        let mut count = 0;
        for (id, vector) in vectors {
            let v: [f32; 128] = match vector.try_into() {
                Ok(v) => v,
                Err(_) => continue,
            };
            vecs.push((id, v));
            count += 1;
        }
        count
    }

    pub fn search(&self, query: &[f32], top_k: u32) -> Vec<SearchResult> {
        let vecs = self.vectors.read().expect("Lock poisoned");
        let k = top_k as usize;
        let mut heap: BinaryHeap<(f64, u64)> = BinaryHeap::new();
        for &(id, ref v) in vecs.iter() {
            let dist = l2_distance(query, &v[..]);
            heap.push((dist, id));
            if heap.len() > k {
                heap.pop();
            }
        }
        let mut results: Vec<SearchResult> = heap.into_iter()
            .map(|(distance, id)| SearchResult { id, distance })
            .collect();
        results.sort_unstable_by(|a, b| a.distance.partial_cmp(&b.distance).unwrap());
        results
    }
}

