pub fn l2_distance(a: &[f32], b: &[f32]) -> f64 {
    debug_assert_eq!(a.len(), b.len());
    let mut sum: f64 = 0.0;
    let n = a.len();
    for i in 0..n {
        let diff = a[i] as f64 - b[i] as f64;
        sum += diff * diff;
    }
    sum.sqrt()
}

