#[target_feature(enable = "avx512f")]
unsafe fn l2_distance_avx512(a: &[f32], b: &[f32]) -> f64 {
    debug_assert_eq!(a.len(), b.len());
    debug_assert_eq!(a.len(), 128);

    let mut sum_sq = _mm512_setzero_ps();

    let a_ptr = a.as_ptr();
    let b_ptr = b.as_ptr();

    for i in (0..128).step_by(16) {
        let va = _mm512_loadu_ps(a_ptr.add(i) as *const f32);
        let vb = _mm512_loadu_ps(b_ptr.add(i) as *const f32);
        let diff = _mm512_sub_ps(va, vb);
        let sq = _mm512_mul_ps(diff, diff);
        sum_sq = _mm512_add_ps(sum_sq, sq);
    }

    let sum_sq_f32 = reduce_add_ps(sum_sq);
    sum_sq_f32.sqrt() as f64
}

