        let storage = self.storage.read().unwrap();
        let n = storage.ids.len();
        let k = std::cmp::min(top_k as usize, n);
        if k == 0 || n == 0 {
            return vec![];
        }

        // Parallel compute all sq distances
        let candidates: Vec<(f64, u64)> = storage.ids.par_iter().enumerate().map(|(i, &id)| {
            let offset = i * 128;
            let v_slice = unsafe { std::slice::from_raw_parts(storage.data.as_ptr().add(offset), 128) };
