#[target_feature(enable = "avx512f")]
unsafe fn sq_l2_distance_unchecked(ap: *const f32, bp: *const f32) -> f64 {
    let mut sum_sq = _mm512_setzero_ps();

    for i in 0..8 {
        let offset = i * 16;
        let va = _mm512_loadu_ps(ap.add(offset));
        let vb = _mm512_loadu_ps(bp.add(offset));
        let diff = _mm512_sub_ps(va, vb);
        let sq = _mm512_mul_ps(diff, diff);
        sum_sq = _mm512_add_ps(sum_sq, sq);
    }

    let hsum = reduce_add_ps(sum_sq);
    f64::from(hsum)
}

#[target_feature(enable = "avx512f")]
unsafe fn reduce_add_ps(v: __m512) -> f32 {
    let sum0 = _mm512_extractf32x4_ps(v, 0);
    let sum1 = _mm512_extractf32x4_ps(v, 1);
    let sum2 = _mm512_extractf32x4_ps(v, 2);
    let sum3 = _mm512_extractf32x4_ps(v, 3);

    let sum01 = _mm_add_ps(sum0, sum1);
    let sum23 = _mm_add_ps(sum2, sum3);
    let sum_all = _mm_add_ps(sum01, sum23);

    let sum_hi = _mm_movehl_ps(sum_all, sum_all);
    let sum_reduced = _mm_add_ps(sum_all, sum_hi);
    let mut sum_hadd = _mm_hadd_ps(sum_reduced, sum_reduced);
    sum_hadd = _mm_hadd_ps(sum_hadd, sum_hadd);

    _mm_cvtss_f32(sum_hadd)
}

