#[inline(always)]
pub fn l2_distance(a: &[f32], b: &[f32]) -> f64 {
    sq_l2_distance(a, b).sqrt()
}

#[inline(always)]
pub fn sq_l2_distance(a: &[f32], b: &[f32]) -> f64 {
    unsafe { sq_l2_avx512(a.as_ptr(), b.as_ptr()) }
}

#[target_feature(enable = "avx512f")]
unsafe fn sq_l2_avx512(ap: *const f32, bp: *const f32) -> f64 {
    let mut sum_sq = _mm512_setzero_ps();

    for i in 0..8 {
        let va = _mm512_loadu_ps(ap.add(i * 16));
        let vb = _mm512_loadu_ps(bp.add(i * 16));
        let diff = _mm512_sub_ps(va, vb);
        let sq = _mm512_mul_ps(diff, diff);
        sum_sq = _mm512_add_ps(sum_sq, sq);
    }

    let sum_f32 = hsum_ps(sum_sq);
    f64::from(sum_f32)
}

#[target_feature(enable = "avx512f")]
unsafe fn hsum_ps(v: __m512) -> f32 {
    let sum0 = _mm512_extractf32x4_ps::<0>(v);
    let sum1 = _mm512_extractf32x4_ps::<1>(v);
    let sum2 = _mm512_extractf32x4_ps::<2>(v);
    let sum3 = _mm512_extractf32x4_ps::<3>(v);

    let sum01 = _mm_add_ps(sum0, sum1);
    let sum23 = _mm_add_ps(sum2, sum3);
    let sum = _mm_add_ps(sum01, sum23);

    let sumh = _mm_movehl_ps(sum, sum);
    let sumh2 = _mm_add_ps(sum, sumh);
    let mut sh = _mm_hadd_ps(sumh2, sumh2);
    sh = _mm_hadd_ps(sh, sh);
    _mm_cvtss_f32(sh)
}

use std::arch::x86_64::*;

#[inline(always)]
pub fn sq_l2_distance(a: &[f32], b: &[f32]) -> f64 {
    if std::arch::is_x86_feature_detected!("avx512f") {
        unsafe { sq_l2_avx512(a.as_ptr(), b.as_ptr()) }
    } else {
        scalar_sq_l2(a, b)
    }
}

#[target_feature(enable = "avx512f")]
unsafe fn sq_l2_avx512(aptr: *const f32, bptr: *const f32) -> f64 {
    let mut sum = 0.0f64;
    for i in 0..8 {
        let va = _mm512_loadu_ps(aptr.add(i * 16));
        let vb = _mm512_loadu_ps(bptr.add(i * 16));
        let diff = _mm512_sub_ps(va, vb);
        let sq = _mm512_mul_ps(diff, diff);
        sum += horizontal_sum(sq) as f64;
    }
    sum
}

unsafe fn horizontal_sum(v: __m512) -> f32 {
    let sum0 = _mm512_extractf32x4_ps::<0>(v);
    let sum1 = _mm512_extractf32x4_ps::<1>(v);
    let sum2 = _mm512_extractf32x4_ps::<2>(v);
    let sum3 = _mm512_extractf32x4_ps::<3>(v);
    let sum01 = _mm_add_ps(sum0, sum1);
    let sum23 = _mm_add_ps(sum2, sum3);
    let sum_ab = _mm_add_ps(sum01, sum23);
    let sum_high = _mm_movehl_ps(sum_ab, sum_ab);
    let sum_a = _mm_add_ps(sum_ab, sum_high);
    let sum_b = _mm_hadd_ps(sum_a, sum_a);
    let sum_c = _mm_hadd_ps(sum_b, sum_b);
    _mm_cvtss_f32(sum_c)
}

fn scalar_sq_l2(a: &[f32], b: &[f32]) -> f64 {
    let mut sum = 0.0f64;
    for i in 0..128 {
        let d = (a[i] - b[i]) as f64;
        sum += d * d;
    }
    sum
}

use crate::api::SearchResult;
use crate::distance::sq_l2_distance;
use rayon::prelude::*;
use std::sync::RwLock;
use std::cmp::Ordering;

#[derive(Debug)]
struct Storage {
    ids: Vec<u64>,
    data: Vec<f32>,
}

pub struct VectorDB {
    storage: RwLock<Storage>,
}

impl VectorDB {
    pub fn new() -> Self {
        Self {
            storage: RwLock::new(Storage {
                ids: Vec::new(),
                data: Vec::new(),
            }),
        }
    }

    pub fn insert(&self, id: u64, vector: Vec<f32>) {
        if vector.len() != 128 {
            return;
        }
        let mut storage = self.storage.write().unwrap();
        storage.ids.push(id);
        storage.data.extend_from_slice(&vector);
    }

    pub fn bulk_insert(&self, mut vectors: Vec<(u64, Vec<f32>)>) -> usize {
        let mut storage = self.storage.write().unwrap();
        let initial_len = storage.ids.len();
        let reserve_count = vectors.len();
        storage.ids.reserve(reserve_count);
        storage.data.reserve(reserve_count * 128);
        let mut count = 0;
        for (id, vector) in vectors.drain(..) {
            if vector.len() == 128 {
                storage.ids.push(id);
                storage.data.extend_from_slice(&vector);
                count += 1;
            }
        }
        count
    }

    pub fn search(&self, query: &[f32], top_k: u32) -> Vec<SearchResult> {
        let storage = self.storage.read().unwrap();
        let n = storage.ids.len();
        let k = std::cmp::min(top_k as usize, n);
        if k == 0 || n == 0 {
            return vec![];
        }

        let num_threads = 4;
        let chunk_size = (n + num_threads - 1) / num_threads;
        let partial_topks: Vec<Vec<(f64, u64)>> = (0..num_threads).into_par_iter().map(|tid| {
            let start = tid * chunk_size;
            let end = std::cmp::min(start + chunk_size, n);
            let mut local_topk: Vec<(f64, u64)> = Vec::with_capacity(k);
            for i in start..end {
                let id = storage.ids[i];
                let offset = i * 128;
                let v_slice = unsafe {
                    std::slice::from_raw_parts(storage.data.as_ptr().add(offset), 128)
                };
                let sq_dist = sq_l2_distance(query, v_slice);
                let insert = if local_topk.len() < k {
                    true
                } else {
                    sq_dist < local_topk.last().unwrap().0
                };
                if insert {
                    if local_topk.len() == k {
                        local_topk.pop();
                    }
                    local_topk.push((sq_dist, id));
                    local_topk.sort_unstable_by(|a, b| a.0.partial_cmp(&b.0).unwrap_or(Ordering::Equal));
                }
            }
            local_topk
        }).collect();

        let mut all_candidates: Vec<(f64, u64)> = partial_topks.into_iter().flatten().collect();
        all_candidates.sort_unstable_by(|a, b| a.0.partial_cmp(&b.0).unwrap_or(Ordering::Equal));
        if all_candidates.len() > k {
            all_candidates.truncate(k);
        }

        all_candidates.into_iter()
            .map(|(sq_dist, id)| SearchResult {
                id,
                distance: sq_dist.sqrt(),
            })
            .collect()
    }
}
